from abc import ABC, abstractmethod

class Vehicle(ABC):
    def __init__(self, make, model, year, vin):
        self.make = make                    # Public attribute for vehicle make
        self.model = model                  # Public attribute for vehicle model
        self.year = year                    # Public attribute for year of manufacture
        self.__vin = vin                    # Private attribute for vehicle identification number

    @abstractmethod
    def start(self):
        pass                                # Abstract method to start the vehicle

    @abstractmethod
    def stop(self):
        pass                                # Abstract method to stop the vehicle

    def display_info(self):
        print(f"Make: {self.make}")
        print(f"Model: {self.model}")
        print(f"Year: {self.year}")
        print(f"VIN: {self.__vin}")

class Car(Vehicle):
    def __init__(self, make, model, year, vin, trunk_capacity):
        super().__init__(make, model, year, vin)  # Call to superclass constructor
        self.trunk_capacity = trunk_capacity       # Additional attribute for trunk capacity

    def start(self):
        print("Car has started.")               # Implementation of start method

    def stop(self):
        print("Car has stopped.")               # Implementation of stop method

    def display_info(self):
        super().display_info()                   # Call to display_info method from Vehicle class
        print(f"Trunk Capacity: {self.trunk_capacity} liters")

class Motorcycle(Vehicle):
    def __init__(self, make, model, year, vin, seat_height):
        super().__init__(make, model, year, vin)  # Call to superclass constructor
        self.seat_height = seat_height            # Additional attribute for seat height

    def start(self):
        print("Motorcycle has started.")         # Implementation of start method

    def stop(self):
        print("Motorcycle has stopped.")         # Implementation of stop method

    def display_info(self):
        super().display_info()                   # Call to display_info method from Vehicle class
        print(f"Seat Height: {self.seat_height} cm")

# Do not modify the code below. This function will be called during testing.
def default_test():
    car = Car("Toyota", "Camry", 2021, "1HGBH41JXMN109186", 500)
    motorcycle = Motorcycle("Harley-Davidson", "Street 750", 2020, "1HD1KBB14DB123456", 75)

    car.start()
    car.display_info()
    car.stop()

    motorcycle.start()
    motorcycle.display_info()
    motorcycle.stop()
